args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT (xsd:integer(?attendance) AS ?numAtt) ?attendance
WHERE {
  {  # World Series 2011
    ?series wdt:P31 wd:Q160237 .
    ?series wdt:P585 ?seriesDate .
    ?game wdt:P361 ?series ;
          wdt:P1110 ?attendance .
    FILTER(YEAR(?seriesDate) = 2011)
    {
      ?game wdt:P54 wd:Q504309
    }
    UNION
    {
      ?game wdt:P404 wd:Q504309
    }
  }
  UNION
  {  # NLCS years
    ?series wdt:P31 wd:Q191121 .
    ?series wdt:P585 ?seriesDate .
    ?game wdt:P361 ?series ;
          wdt:P1110 ?attendance .
    FILTER(YEAR(?seriesDate) IN (1982, 2006, 2011, 2013))
    {
      ?game wdt:P54 wd:Q504309
    }
    UNION
    {
      ?game wdt:P404 wd:Q504309
    }
  }
  FILTER (?attendance > 0)
}
ORDER BY DESC(?numAtt)
LIMIT 1
